  console.error('Uncaught Exception:', err);
  process.exit(1); // Fail loudly
});

process.on('unhandledRejection', (reason) => {
  console.error('Unhandled Rejection:', reason);
  process.exit(1);
});
```

---

### 8. 🧹 CORS Policy Not Defined
Without an explicit CORS policy, the behavior depends on the environment. Use the `cors` package and configure it explicitly:

```js
const cors = require('cors');
app.use(cors({
  origin: ['https://your-trusted-domain.com'],
  methods: ['GET'],
}));
```

Avoid `cors()` with no options in production, as it allows **all origins**.

---

